// UserExists is the debounced dedupe check for the create-user form (global —
// username/email uniqueness is not tenant-scoped).
func (r *queryResolver) UserExists(ctx context.Context, username *string, email *string) (bool, error) {
	un, em := derefString(username), derefString(email)
	if un == "" && em == "" {
		return false, nil
	}
	q := r.Ent.User.Query()
	switch {
	case un != "" && em != "":
		q = q.Where(user.Or(user.Username(un), user.Email(em)))
	case un != "":
		q = q.Where(user.Username(un))
	default:
		q = q.Where(user.Email(em))
	}
	return q.Exist(ctx)
}
